var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"6개월 뒤","JPN":"6か月後","ENG":"6 months later","TWN":"6個月後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제7 방위선 탈환 작전","JPN":"人類統合防衛軍による第7防衛線奪還作戦","ENG":"Operation Takeover United Humankind Defense Force's 7th Defense Line","TWN":"奪回人類共同保衛軍第七防線作戰"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"이 고지만 되찾으면, 네피림 사태 때 잃어버린 제7 방위선을 회복할 수 있다!","JPN":"このポイントさえ取り返せば、ネフィリム事件の際に失われた第7防衛線を回復させられる！","ENG":"If we take this high ground, we will be able to reclaim the 7th Defense Line, which we lost during the Nephil incident!","TWN":"只要奪回這個高地，我們就有希望恢復在諾菲力事件中丟失的第七防線了！"},"stage":{"bg":"PROLOGUE_01","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"목숨이 끝나는 한이 있더라도! 빌어먹을 침식체들에게 인간의 저력을 보여주는 거다!","JPN":"命を落とそうとも！　クソッたれの侵食体どもに人間の底力を見せてやるんだ！","ENG":"Even if it means sacrificing our lives! We must show those C.O. bastards what humans are capable of!","TWN":"一定要讓這些該死的侵蝕體們嚐嚐人類的厲害！哪怕我們全部犧牲！"},"stage":{"bg":"PROLOGUE_01","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"제기랄, 총알이 다 떨어졌어! 누구 총알 가진 거 더 없어!?","JPN":"くそっ、弾切れだ！　誰かまだ弾が残っている者はいないか！？","ENG":"Dammit! I'm outta ammo! Does anyone have a mag?!","TWN":"可惡，沒子彈了！誰還有子彈？！"},"stage":{"bg":"PROLOGUE_01","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"이봐, 정신 차려!! 이제 고지가 코 앞인데 여기서 죽으면 어쩌자는 거야!!","JPN":"おい、しっかりしろ！！　目標地点まであと少しだというのに、ここで死んでどうする！！","ENG":"Hey, pull yourself together!! We're almost there, you can't die here!!","TWN":"喂，醒醒！！差一步就能奪回高地了，可不能在這裡倒下！！"},"stage":{"bg":"PROLOGUE_01","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"이거나 쳐 먹어라, 이 괴물 자식들아!!","JPN":"これでも食らえ、この化け物ども！！","ENG":"Eat this, you damn monsters!!","TWN":"你們這些怪物，吃我一槍！！"},"stage":{"bg":"PROLOGUE_01","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GUARD_EXILER_NPC_B","text":{"KOREA":"크윽, 이봐! 항공 지원은 아직이야?","JPN":"くっ、おい！　航空支援はまだなのか？","ENG":"Kgh, hey! What's the ETA for the air support?!","TWN":"咳呃，喂！空中支援還沒到嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L23_1","type":"dialog","speaker":"GUARD_EXILER_NPC_B","text":{"KOREA":"예상보다 침식체의 숫자가 너무 많아! 지상 병력으로만 제압하기는 어렵겠어!","JPN":"予想以上に侵食体の数が多い！　地上兵力だけでは制圧は無理だ！","ENG":"There are too many C.O.s here! We can't kill them all by ourselves!","TWN":"侵蝕體的數量超出預想的太多了！只靠地面兵力很難壓制他們！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GUARD_EXILER_NPC_C","text":{"KOREA":"제기랄, 이럴 때 카운터가 있었더라면!","JPN":"くそ、こんな時にカウンターがいればな！","ENG":"Damn it, if only there was a Counter!","TWN":"可惡，這種時候有制裁者就好了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_C","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L29_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"시끄러워, 불평할 시간이 있으면 총알 한 발이라도 더 쏴 갈기라고!","JPN":"うるせえ、文句を言っている暇があるなら、弾を一発でも多くぶち込むことに集中しろ！","ENG":"Shut it! Shoot 'em if you've got time to whine!","TWN":"吵死了，有這抱怨的時間，還不如多射一發子彈!"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"뭐지? 방금 장갑차가 꿈틀거렸던 것 같은데……?","JPN":"なんだ？　今装甲車が浮き上がったような……？","ENG":"Huh? Is it me, or did that armored vehicle just twitch...?","TWN":"嗯？剛剛裝甲車好像晃了一下……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"이런 제기랄!!","JPN":"くそ、まじかっ！！","ENG":"Goddammit!","TWN":"見鬼！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"당장 도망쳐!! 3종이 땅 속에서 튀어나왔다!!","JPN":"今すぐ逃げろ！！　第3種が地面から飛び出してきたぞ！！","ENG":"RUN!! A Category 3 just appeared from right beneath us!!","TWN":"在我們下面！3類侵蝕體從地底冒出來了！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"읏! 크아아아악……!!","JPN":"くっ！　ぐああああっ……！！","ENG":"Ngh! Graaah...!!","TWN":"呃！啊啊啊啊啊……！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GUARD_EXILER_NPC_B","text":{"KOREA":"앨런!!","JPN":"アラン！！","ENG":"ALLAN!!","TWN":"艾倫！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_C","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GUARD_EXILER_NPC_C","text":{"KOREA":"이런 개자식이!!","JPN":"この野郎！！","ENG":"Why you sons of...!!","TWN":"該死的侵蝕體！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_C","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"하아, 하아, 이렇게 침식체 놈들한테 잡아먹힐 바에는 차라리……","JPN":"はぁ、はぁ、このまま侵食体どもに食われるくらいなら……","ENG":"*Huff*... *Huff*... I'd rather die than get eaten by these C.O.s–","TWN":"哈啊，哈啊，與其就這樣被侵蝕體們吃掉，還不如……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mmm?","TWN":"嗯？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"현장의 전 대원. 들립니까?","JPN":"現場の全隊員へ。聞こえていますか？","ENG":"All units, do you hear me?","TWN":"現場的全體隊員，能聽到嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저희가 도착했으니 이제 안심하세요.","JPN":"私たちが来ましたから、もう安心してください。","ENG":"Rest assured that we have arrived.","TWN":"我們已經抵達，各位可以放心了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GUARD_EXILER_NPC_C","text":{"KOREA":"됐다! 항공 지원이 도착했어!","JPN":"よし！　航空支援の到着だ！","ENG":"Yes! Air support's finally here!","TWN":"太好了！空中支援到了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_C","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GUARD_EXILER_NPC_B","text":{"KOREA":"뉴 오하이오? 말로만 듣던 델타 세븐의 기함인가?","JPN":"ニューオハイオ？　あれが噂のデルタセブンの旗艦なのか？","ENG":"New Ohio? Isn't that Delta Seven's Flagship?","TWN":"那是新俄亥俄？傳說中的第七三角洲部隊艦船？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_C","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GUARD_EXILER_NPC_B","text":{"KOREA":"그렇다는 말은, <color=#ffd34c>크로스로드의 영웅</color>들?","JPN":"ということは、<color=#ffd34c>クロスロードの英雄</color>たちが？","ENG":"That means... the <color=#ffd34c>heroes of Crossroads</color>?","TWN":"也就是說，他們是<color=#ffd34c>十字路口的英雄</color>？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_C","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"현장에 전 대원, 지금으로부터 정확히1분 뒤, 전장에 전방위 폭격이 있을 예정입니다.","JPN":"現場の全隊員へ。ただ今より正確に1分後、戦場に全方位爆撃を行います。","ENG":"To all ground units, in exactly 60 seconds, the field will be bombarded.","TWN":"現場全體隊員請注意，從當前時間開始，1分鐘之後，我們將會對戰場實施全方位的轟炸。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전 대원은 지금 즉시 부상자들을 데리고 안전한 곳으로 대피해주세요.","JPN":"全隊員は今すぐに負傷者を連れ、安全な場所に避難してください。","ENG":"All units are to immediately take the injured and evacuate the premises to a safe location.","TWN":"全體隊員，現在請立即將傷患撤離至安全區。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"긴급 작전 코드, 프리덤 스트라이크에 의거, 현 시간부로 전장 소각을 개시하겠습니다.","JPN":"緊急作戦コード、フリーダムストライクに基づき、現時刻をもって戦場の焼却を開始します。","ENG":"In accordance with the emergency operation code, Freedom Strike, the area will be incinerated.","TWN":"根據緊急作戰代碼，自由之擊，即刻起將摧毀戰場！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"3…… 2…… 1, 전장 소각 개시!","JPN":"3……2……1、戦場焼却開始！","ENG":"In 3... 2... 1! Incinerate the battlefield!","TWN":"3……2……1，開始摧毀戰場！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"예이, 예이~ 전장 소각 개시~","JPN":"はい、はい～戦場の焼却を開始～","ENG":"Yeah, yeah. Incinerating the battlefield.","TWN":"是是是，遵命～～開始摧毀戰場～"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"지금이다! 침식체의 기세가 누그러졌어!!","JPN":"今だ！　侵食体が怯んだぞ！！","ENG":"Now's our chance! The C.O.s are weakening!!","TWN":"就是現在！侵蝕體的氣勢變弱了!!"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"단숨에 돌입한다!","JPN":"一気に突入だ！","ENG":"Charge!","TWN":"一口氣攻過去！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"전장의 1종 2종 침식체 70% 소멸 확인.","JPN":"戦場の第1種、第2種侵食体の70％の消滅を確認。","ENG":"Obliterated 70% of Category 1 and 2 C.O.s.","TWN":"確認已消滅戰場上70%的1、2類侵蝕體。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L32_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"그치만 소령, 가장 중요한 3종은 아직 멀쩡한데?","JPN":"でも少佐、肝心の第3種がまだぴんぴんしてるけど？","ENG":"But Major, the Category 3 one is still alive and well.","TWN":"可是少校，最主要的3類侵蝕體仍毫髮無損。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니요, 계산대로예요. 남은 침식체는 저희가 직접 강하해서 섬멸합니다.","JPN":"はい、計算通りです。残りの侵食体は私たちが直接降下し、殲滅します。","ENG":"No, this is all according to plan. We will rappel down and eliminate the remaining C.O.s ourselves.","TWN":"沒關係，這都在預料之中。剩下的侵蝕體會由我們親自殲滅。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"너무 위험한 거 아니야, 소령! 매뉴얼대로라면 3종은 국가 재난급이라고!","JPN":"それは危険すぎるわ、少佐！　マニュアル通りなら第3種は国家災害クラスなのよ！","ENG":"Isn't that too risky, Major? A Category 3 is a national disaster according to the manual!","TWN":"啊？太危險了，少校！按照手冊上說的，3類侵蝕體可是國家災難級的！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"이제 소령은 지휘관이야! 조직을 이끄는 사람이 함부로 실전에 나서는 건 위험해!","JPN":"少佐はもう指揮官なの！　組織を率いる者が下手に戦場に出るのは危険すぎる！","ENG":"You're the commanding officer, Major! A person like you entering the battlefield is far too dangerous!","TWN":"少校現在是指揮官！身為帶領組織的領袖，輕易就出戰太冒險了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니요. <color=#ffd34c>그 세계</color>에서 네피림을 쓰러트린 이후, 전 깨달았어요.","JPN":"いいえ。<color=#ffd34c>あの世界</color>でネフィリムを倒してから、私は気づいたんです。","ENG":"No. I realized something after they defeated the Nephil in <color=#ffd34c>the other world</color>.","TWN":"不。在<color=#ffd34c>那個世界</color>擊敗了諾菲力之後，我想明白了一件事。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"늦었을지도 모르지만, 우리는 반드시 강해져야만 해요.","JPN":"もう遅いかもしれないけど、私たちは強くならなければなりません。","ENG":"It might be too late, but we must get stronger.","TWN":"或許現在這麼說為時已晚，但是，我們必須變得更強大。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"모두가 목숨을 걸고 번 20년이라는 시간을 결코 헛되이 해서는 안 되니까요.","JPN":"みんなが命を懸けて稼いだ20年間の猶予を、決して無駄にするわけにはいきませんから。","ENG":"We cannot waste the 20 years that our fallen comrades have bought us.","TWN":"大家拼上性命換回來的20年時間，絕不能白白浪費。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까, 이제와서 고작 3종 때문에 발이 묶여 있을 시간 같은 건 없어요!","JPN":"今更第3種ごときに足止めを食らっている時間などありません！","ENG":"In other words, we have no time to be struggling over some Category 3 C.O.s!","TWN":"所以，現在可不能因為區區3類侵蝕體就綁手綁腳！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"자! 가죠, 시영 씨!","JPN":"さぁ！　行きましょう、シノンさん！","ENG":"Shiyoung! It's time!","TWN":"好了！我們出發吧，時雨！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이제 우리 차례에요! 강하 준비 아직 멀었어요?","JPN":"私たちの番ですよ！　降下準備はまだなんですか？","ENG":"It's our turn now! Are you ready to rappel down?","TWN":"現在該輪到我們了！準備好登陸！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에에~? 그치만 이건 계약이랑 다른걸요, 카린 양?","JPN":"ええ～だって、これは契約内容と違うじゃないですか、カリンさん？","ENG":"Huh? But this isn't what I signed up for, Karin.","TWN":"哎呀～？這可和合同說的不一樣呢，卡琳？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아무리 그래도 3종은 추가 요금이 붙을 것 같은데요?","JPN":"さすがに第3種は追加料金が発生しますよ？","ENG":"I think it'll cost you extra if you want me to deal with a Category 3.","TWN":"不管怎麼說，處理3類侵蝕體得支付額外佣金吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"기각합니다!","JPN":"却下します！","ENG":"Overruled!","TWN":"我拒絕！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신, 매달 당신한테 지불하는 의뢰비가 내 월급보다 많은 거 알아!?","JPN":"あなたに毎月支払っている依頼料は私の給料より多いんですよ？","ENG":"Do you even know that the amount you're paid monthly is more than my pay stub?!","TWN":"你知道的吧？我每個月向你支付的委託費可比我自己的工資還要高？！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이제 고집 그만 부리고, 델타 세븐에 정식으로 입대하라고!","JPN":"いい加減デルタセブンに正式に入隊しなさい！","ENG":"Stop being stubborn and officially join Delta Seven already!","TWN":"現在收起你的固執，正式加入第七三角洲部隊！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그게 무슨 소리예요, 카린 양. 저는 세계를 구한 일류 용병이라고요.","JPN":"いやいや、カリンさん。私は世界を救った一流の傭兵なんですよ。","ENG":"I don't know what you're talking about, Karin. But I do know that I'm a first-class mercenary who just saved the world.","TWN":"我聽不懂你在說什麼，卡琳。我可是拯救世界的頂級傭兵呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그러니까 몸값이 비싼 건 당연한 거 아니겠어요, 엣헴!","JPN":"私の賃金が高いのは当り前なのでは？　えっへん！","ENG":"So, that gives me leverage to increase my worth, no? Ahem!","TWN":"所以，身價昂貴一點很正常啊，哼哼！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사이버캣, 해치 좀 열어줄래요?","JPN":"サイバーキャット、ハッチを開けてくれますか？","ENG":"Cyber Cat, could you open the hatch for us?","TWN":"賽博貓，麻煩你幫我們打開一下艙口。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아무래도 시영 씨의 강하를 도와드려야 할 것 같으니까.","JPN":"どうやらシノンさんの降下をお手伝いしないといけないようなので。","ENG":"I think Shiyoung needs some help rappelling down today.","TWN":"看來時雨的登陸需要些小小的説明。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};